import pytest
import requests

BASE_URL = "<base_url>"

@pytest.fixture
def invalid_auth_headers():
    return {"Authorization": "Bearer <expired_or_invalid_token>"}

@pytest.fixture
def kyc_payload_valid():
    return <fixture_kyc_payload_valid>

def test_kyc_refresh_unauthorised_token_returns_403(invalid_auth_headers, kyc_payload_valid):
    resp = requests.post(
        f"{BASE_URL}/kyc/refresh",
        json=kyc_payload_valid,
        headers=invalid_auth_headers,
        timeout=10
    )
    assert resp.status_code in (401, 403), (
        f"Expected 401 or 403 for unauthorised request, got {resp.status_code}"
    )
    body = resp.json()
    error_code = body.get("error_code", "").upper()
    assert any(kw in error_code for kw in ("UNAUTHORI", "FORBIDDEN", "AUTH")), (
        f"Unexpected error_code: {error_code}"
    )
